public EventResponseDTO createEvent(UUID userId, EventRequestDTO dto) {

        validate(dto);

        Users user = usersRepository.findById(userId).orElseThrow();

        Event event = new Event();
        event.setTitle(dto.getTitle().trim());
        event.setDescription(dto.getDescription());
        event.setCategory(dto.getCategory());
        event.setCoverPhotoUrl(dto.getCoverPhotoUrl());
        event.setCoverPhotoPublicId(dto.getCoverPhotoPublicId());
        event.setEventDate(dto.getEventDate());
        event.setZone(dto.getZone());
        event.setExactAddress(dto.getExactAddress());
        event.setLatitude(dto.getLatitude());
        event.setLongitude(dto.getLongitude());
        event.setFree(dto.isFree());
        event.setPrice(dto.isFree() ? null : dto.getPrice());
        event.setMinGuests(Math.max(1, dto.getMinGuests()));
        event.setMaxGuests(dto.getMaxGuests());
        event.setMinAge(dto.getMinAge() > 0 ? dto.getMinAge() : 18);
        event.setMaxAge(dto.getMaxAge() > 0 ? dto.getMaxAge() : 99);
        event.setTargetAudience(dto.getTargetAudience());
        event.setStatus(EventStatus.OPEN);
        event.setCreator(user);
        event.setCreatedAt(Instant.now());
        event.setCategoryDetailsJson(serializeDetails(dto.getCategoryDetails()));
